command.text:

insert into ctdmku select * from @ctdmku
insert into ctdmku2 select * from @ctdmku2

        &UnitPostInsert;

        /* <flatten type="Javascript"> */
var f = this, o = f.getItem('ctdmku')._controlBehavior, g2 = f.getItem('ctdmku2')._controlBehavior, t2 = 0;
for (var i = 0; i < o._rowCount - 1; i++) {
  var c = o._getColumnOrder('ngay_hl');
  var v = o._getItemValue(i + 1, c);
  for (var j = i + 1; j < o._rowCount; j++) {
    var d = o._getItemValue(j + 1, c);
    if ($func.compareDateTimeValue(v, d)) {
      f._checked = false;
      o._errorObject = o._getItem(j + 1, c);
      break;
    }
  }
  if (!f._checked) break;
}
if (f._checked) {
  var l2 = g2._getColumnOrder('ngay_tt');
  for (var i = 0; i < g2._rowCount - 1; i++) {
    var v = g2._getItemValue(i + 1, l2);
    for (var j = i + 1; j < g2._rowCount; j++) {
      var d = g2._getItemValue(j + 1, l2);
      if ($func.compareDateTimeValue(v, d)) {
        f._checked = false;
        g2._errorObject = g2._getItem(j + 1, l2);
        t2 = 1;
        break;
      }
    }
    if (!f._checked) break;
  }
}
if (f._checked) {
  var c = o._getColumnOrder('line_nbr');
  var c2 = g2._getColumnOrder('line_nbr');
  for (var i = 0; i < o._rowCount; i++) {
    o._setItemValue(i + 1, c, i + 1);
  }
  for (var i = 0; i < g2._rowCount; i++) {
    g2._setItemValue(i + 1, c2, i + 1);
  }
}
else {
  if (t2 == 0) {
    var errorMessage = (f._language == 'v' ? 'Trường <span class="Highlight">Ngày hiệu lực</span> giá trị nhập không hợp lệ, giá trị này đã được khai báo.' : 'Field <span class="Highlight">Effective Date</span> has invalid value, its value already exists.');
    $func.hideWait(f.get_id());
    f.focus('ctdmku');
    $message.show(errorMessage, String.format('$find(\'{0}\')._errorObject.focus()', o.get_id()));
  }
  else {
    var errorMessage = (f._language == 'v' ? 'Trường <span class="Highlight">Ngày thanh toán</span> giá trị nhập không hợp lệ, giá trị này đã được khai báo.' : 'Field <span class="Highlight">Payment Date</span> has invalid value, its value already exists.');
    $func.hideWait(f.get_id());
    f.focus('ctdmku2');
    $message.show(errorMessage, String.format('$find(\'{0}\')._errorObject.focus()', g2.get_id()));
  }
}
/* </flatten> */
        &UnitCheck;

script.text:
      &ScriptQueryData;

function active$FormLoanContract(f) {
  f.add_onResponseComplete(on$FormLoanContract$ResponseComplete);
  f._tabContainer.add_activeTabChanged(onTabChanged&Identification;);
  f._tabContainer._loaded = true;
}
function close$FormLoanContract(f) {
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onTabChanged&Identification;);} catch (ex) {}
  try {f.remove_onResponseComplete(on$FormLoanContract$ResponseComplete)} catch (ex) {}
}
/* <flatten type="Javascript"> */
function on$FormLoanContract$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'ma_ku, so_ku');
      break;
    default:
      break;
  }
}
function onChangeLoanContract(o) {o.parentForm.getItem('so_ku').value = o.value;}
function onChangeLoanDate(o) {o.parentForm.getItem('ngay_ku1').value = o.value;}
/* </flatten> */
function onTabChanged&Identification;(sender, e) {sender.parentForm.focusWhenTabChanged(['ngay_ku', 'ctdmku', 'ctdmku2'&UnitTab;, 'ghi_chu']);}

